// This loop processes every row coming from your Google Sheet
for (const item of $input.all()) {
  const docMap = {
    "Orthodontics": { name: "Dr. General Dentist", bio: "MSc London, specializing in Invisalign." },
    "Dental implants": { name: "Dr. Orthodontist", bio: "Fellowship in Vienna, over 3,000 procedures." },
    "Cosmetic dentistry": { name: "Dr. Periodontist", bio: "Award-winning smile designer." },
    "Paediatric dentistry": { name: "Dr. Oral Surgeon", bio: "UCL Diploma, expert in children's care." },
    "General dentistry": { name: "Dr. Periodontist", bio: "Expert in full mouth rehabilitation." },
    "Root canal therapy": { name: "Dr. Periodontist", bio: "Specialist in painless root canal treatments." },
    "Emergency care": { name: "Dr. Orthodontist", bio: "Expert in urgent oral surgery and pain relief." }
  };

  // Map the doctor based on the Service column
  const selectedService = item.json["Service"];

  // Attach the doctor object to the current item
  item.json.doctor = docMap[selectedService] || { name: "Our Specialist Team", bio: "Expert care for your smile." };
}

return $input.all();

return $input.all().map(item => {
  const val = item.json['Last Notified At'];
  if (!val || val.toString().trim() === '') {
    item.json['Last Notified At'] = '2020-01-01T00:00:00.000Z';
  }
  return item;
});

return $input.all().map(item => {
  const date = item.json['Preffered Date'];
  if (!date || date.toString().trim() === '') {
    item.json['Preffered Date'] = '2000-01-01';
  }
  return item;
});
